.8,"ratingStars":4}},"subnavItems":[{"id":"overview","label":"行程概覽"},{"id":"itinerary","label":"行程安排"},{"id":"details","label":"行程亮點"},{"id":"faq","label":"常見問題"},{"id":"reviews","label":"旅客評價"}],"glanceItems":[{"icon":"camera","label":"拍照表現","value":"高"},{"icon":"mountain","label":"風景精彩度","value":"高"},{"icon":"footprints","label":"步行負擔","value":"中等"},{"icon":"cloud-rain","label":"陰雨適合度","value":"中等"},{"icon":"users","label":"親子友善","value":"適合"},{"icon":"scale","label":"行程節奏","value":"剛好"}],"galleryItems":[{"id":1,"type":"video","src":"https://images.unsplash.com/photo-1596402184320-417e7178b2cd?w=1200&q=80","location":"路線總覽","atmosphere":"一天的風景節奏","alt":"濟州東部海岸路線總覽"},{"id":2,"type":"photo","src":"https://images.unsplash.com/photo-1548013146-72479768bada?w=800&q=80","location":"石景開場","atmosphere":"早晨的火山地景","alt":"濟州石文化公園石雕景觀"},{"id":3,"type":"photo","src":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=800&q=80","location":"日出樂園熔岩洞園區","atmosphere":"沁涼的洞穴質感","alt":"日出樂園熔岩洞園區內部景觀"},{"id":4,"type":"photo","src":"https://images.unsplash.com/photo-1590077428593-a55bb07c4665?w=800&q=80","location":"聚落紋理","atmosphere":"帶著生活感的文化風景","alt":"城邑民俗村"},{"id":5,"type":"photo","src":"https://images.unsplash.com/photo-1596402184320-417e7178b2cd?w=800&q=80","location":"火山口海岸","atmosphere":"視野最開闊的高潮段","alt":"城山日出峰火山口"},{"id":6,"type":"video","src":"https://images.unsplash.com/photo-1469474968028-56623f02e42e?w=800&q=80","location":"開闊海岬步道","atmosphere":"海風吹開心情的那一段","alt":"涉地可支海岸步道"}],"itineraryStops":[{"number":1,"time":"09:00","duration":"60 分鐘","name":"濟州石文化公園","category":"火山地景與石文化","description":"這一站很適合作為整天的開場。先從石文化公園認識濟州「火山島」的性格，後面再看海岸、火山口、熔岩洞與聚落時，感受會更完整，也更有層次。","image":"https://images.unsplash.com/photo-1548013146-72479768bada?w=800&q=80","highlights":["遼闊開展的石雕、石塔與戶外空間","很適合用來理解濟州獨有的石文化","拍照畫面乾淨，取景舒服","館內展示能把火山與地質故事補得更完整"],"timeUsed":["先做簡短導覽，帶大家進入石文化主題","在戶外石景區停留拍照與聽解說","最後視現場節奏安排館內展示或收尾說明"],"whyOnRoute":"先從這裡開始，後面海岸、火山口與熔岩洞的景觀會更有脈絡。","visitBasics":{"hours":"09:00-18:00","closed":"週一","admission":"成人 5,000 韓元 / 青少年 3,500 韓元","walking":"輕鬆到中等"},"convenience":{"restroom":"入口與博物館區域","parking":"可停車"},"smartNotes":{"photo":"這裡更適合拍大景與空間感，不特別適合太近的特寫。","facilities":"前段路線裡，這裡的洗手間與館內設施最完整。","tip":"這一站適合慢慢打開節奏，不建議走成匆忙打卡點。"}},{"number":2,"time":"10:40","duration":"60 分鐘","name":"涉地可支","category":"開闊海岬海岸線","description":"離開石文化公園後，路線正式往外打開。涉地可支把海風、稜線與濟州東海岸的開闊感帶進來，也替中午過後的城山日出峰先鋪好情緒。","image":"https://images.unsplash.com/photo-1469474968028-56623f02e42e?w=800&q=80","highlights":["面海步道與開闊海岬地形","依季節不同可看到花海景觀","燈塔視角與遼闊海景同框","和石文化公園形成很漂亮的視覺反差"],"timeUsed":["抵達後先在入口簡單說明路線","沿著主要海岸步道散步看景","保留拍照時間，再以輕鬆步調折返"],"whyOnRoute":"先把海岸氛圍打開，下午的城山日出峰才會更有主景登場的力道。","visitBasics":{"hours":"24 小時開放","closed":"無","admission":"免費（停車另計）","walking":"輕鬆到中等"},"convenience":{"restroom":"入口區域","parking":"付費停車"},"smartNotes":{"photo":"這裡風大、天空開，側拍通常比正面站定照更好看。","facilities":"設施不多，洗手間主要在入口。","tip":"這一站比前一站更曝曬，風勢與日照感受會明顯許多。"}},{"number":3,"time":"12:00","duration":"60 分鐘","name":"午餐","category":"中段節奏重整","description":"午餐不只是休息，而是整條路線節奏的轉折點。把體力與情緒整理好之後，再去迎接下午最有代表性的城山日出峰，整體體驗會舒服很多。","image":"https://images.unsplash.com/photo-1590077428593-a55bb07c4665?w=800&q=80","highlights":["在最需要的時間點補回體力","剛好銜接海岸散步與午後主景","對不同年齡層的旅客都更友善","讓下半天的節奏更乾淨俐落"],"timeUsed":["抵達用餐地點與安排座位","用餐與短暫休息","整理節奏後出發前往城山日出峰"],"whyOnRoute":"午餐放在這裡，城山日出峰就不會玩得太趕，也更有餘裕。","visitBasics":{"hours":"依餐廳營業時間","closed":"依店家而定","admission":"依產品方案或現場自理","walking":"極少"},"convenience":{"restroom":"餐廳設施","parking":"可停車"},"smartNotes":{"photo":"喜歡拍食物的人，可以把重點放在在地料理。","facilities":"餐廳設施完整。","tip":"中午這一段重點不是快，而是把後半天的體驗整理得更順。"}},{"number":4,"time":"13:15","duration":"90 分鐘","name":"城山日出峰","category":"火山口步道與海女文化","description":"這是整天最具代表性的主景。城山日出峰把火山口地形、海岸尺度與濟州最具辨識度的景觀集中在一起；若時間配合得上，海女表演也會讓這一站更有濟州味。","image":"https://images.unsplash.com/photo-1596402184320-417e7178b2cd?w=800&q=80","highlights":["世界自然遺產級的火山口景觀","山腳與上坡路段都有很強的視野層次","火山地形線條鮮明，是濟州經典代表","結合海女文化脈絡，更能感受在地特色"],"timeUsed":["抵達後先做路線與動線說明","依團體節奏安排主要步行段","保留火山口或山腳觀景，以及海女表演時段的彈性"],"whyOnRoute":"午餐之後安排城山，最能把體力、風景強度與整天情緒推到高點。","visitBasics":{"hours":"07:00-20:00（夏季） / 07:30-19:00（冬季）","closed":"全年開放","admission":"成人 5,000 韓元 / 青少年 2,500 韓元","walking":"若登頂則較有挑戰"},"convenience":{"restroom":"山腳與近山頂區域","parking":"大型停車場"},"smartNotes":{"photo":"大多數時候，帶到火山口與海岸線的大景，會比只拍登頂照更有張力。","facilities":"山腳設施完整，靠近高處則較基本。","tip":"這一站會受到團體步調、天氣與現場人潮影響，實際停留方式可能偏向步行、觀景或表演時段安排。"}},{"number":5,"time":"15:00","duration":"55 分鐘","name":"日出樂園（Ilchulland）","category":"熔岩洞與庭園散步","description":"走完城山日出峰之後，日出樂園會把整天節奏柔和下來。相較於前段的海風與火山口，這裡更涼爽、更收斂，也多了一點庭園散步的舒服感。","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=800&q=80","highlights":["以熔岩洞為核心的庭園型景區","和前一站的開闊感形成鮮明反差","有遮蔭、步調較柔和","很適合作為午後由高潮轉入收尾的過渡"],"timeUsed":["入園後先做簡單路線說明","安排主要熔岩洞或室內主題區參觀","最後在園區短暫散步後集合離開"],"whyOnRoute":"放在城山之後最剛好，它不是主景的開場，而是把高潮之後的節奏收得更漂亮。","visitBasics":{"hours":"09:00-18:00","closed":"依現場公告","admission":"成人 4,000 韓元 / 青少年 2,000 韓元","walking":"中等"},"convenience":{"restroom":"入口處","parking":"可停車"},"smartNotes":{"photo":"室內外光線反差大，只要曝光抓得穩，很容易拍出有氣氛的畫面。","facilities":"入口設施基本完整。","tip":"城山之後來這裡會特別舒服，因為整體步調更集中，也更有遮蔭。"}},{"number":6,"time":"16:20","duration":"40 分鐘","name":"城邑民俗村","category":"聚落紋理與生活感","description":"最後用城邑民俗村收尾，不再追求另一個強景點，而是把視角拉回人的生活。走過石、海岸、火山口與熔岩洞之後，這裡讓整天多了一層更安定也更有歷史溫度的結尾。","image":"https://images.unsplash.com/photo-1590077428593-a55bb07c4665?w=800&q=80","highlights":["茅草屋、石牆與濟州傳統聚落景觀","比起純景點，更有文化與生活感","步調慢，適合邊走邊看細節","和前段自然景觀形成很好的收尾對比"],"timeUsed":["抵達後先說明聚落背景","沿著主要村落路線散步參觀","最後留一些時間做收尾說明與簡單自由看看"],"whyOnRoute":"把最後一站放在這裡，會讓整天在更踏實、更有地方感的氛圍中結束。","visitBasics":{"hours":"白天開放","closed":"無","admission":"免費","walking":"輕鬆，多為平路"},"convenience":{"restroom":"村落中心","parking":"附近可停車"},"smartNotes":{"photo":"這裡更適合拍屋頂線條、石牆紋理與巷道感，不一定要追求正中央的大景。","facilities":"村內設施較基本。","tip":"這一站越從容越好，才更能感受到它作為收尾的味道。"}}],"routeFlowStops":[{"id":"01","name":"石文化公園","theme":"石文化"},{"id":"02","name":"涉地可支","theme":"海岸"},{"id":"03","name":"午餐","theme":"重整"},{"id":"04","name":"城山日出峰","theme":"火山口"},{"id":"05","name":"日出樂園","theme":"庭園"},{"id":"06","name":"民俗村","theme":"文化"}],"routePhases":[{"label":"上午","range":"1-2","theme":"從石文化走向海岸","bgClass":"bg-sky-50/70","textClass":"text-sky-700","dotClass":"bg-sky-500"},{"label":"中段","range":"3-4","theme":"午餐與城山高潮段","bgClass":"bg-amber-50/70","textClass":"text-amber-700","dotClass":"bg-amber-500"},{"label":"收尾","range":"5-6","theme":"庭園與民俗聚落","bgClass":"bg-emerald-50/70","textClass":"text-emerald-700","dotClass":"bg-emerald-500"}],"routeShapeIntro":{"title":"這一天會怎麼走","subtitle":"從石文化到海岸，中午休息後進入城山主景，最後以庭園與聚落收尾。09:00 至 17:00。"},"whyTourWorks":{"bestFor":["第一次來濟州的旅人","情侶夫妻","喜歡一邊玩一邊理解地方故事的人","體力不錯的熟齡旅客"],"lessIdeal":["想完全避開階梯或洞穴的人","推車需求較高的家庭","年紀太小、不適合完整一日行程的孩子"],"routeLogicSections":[{"title":"節奏安排","icon":"sun","iconBg":"bg-amber-50/80","iconColor":"text-amber-600","items":[{"label":"先從石文化開場，不急著直接衝海景","detail":"先用石文化公園把濟州的背景鋪好，後面看到海岸與火山地形時會更有感。"},{"label":"午餐時間剛好卡在最需要的地方","detail":"中午先整理體力，下午再進入城山日出峰，整體感受會更順。"},{"label":"主景放在午餐後，情緒更容易拉高","detail":"把城山安排在午餐後，最有代表性的那一站就能在體力與節奏都比較好的狀態下展開。"}]},{"title":"路線層次","icon":"mountain","iconBg":"bg-sky-50/80","iconColor":"text-sky-600","items":[{"label":"先海岸、後火山口","detail":"涉地可支先把海的感覺打開，接著再由城山日出峰接住整天最強的火山地景。"},{"label":"高潮之後，用庭園把節奏柔下來","detail":"城山之後接日出樂園，剛好把午後的步調收得比較舒服。"},{"label":"最後留給聚落，而不是再追一個大景","detail":"城邑民俗村讓整天在更有人味、更有地方感的氛圍中結束。"}]},{"title":"遇到現場變數時","icon":"wind","iconBg":"bg-slate-50/80","iconColor":"text-slate-600","items":[{"label":"週一不出發","detail":"這條路線不安排週一出團。"},{"label":"最受天氣影響的是海岸與城山段","detail":"涉地可支與城山日出峰是整天最看風勢與天候的兩站。"},{"label":"步行強度可以依現場調整","detail":"城山段會依照團體體力、天氣與現場狀況微調節奏。"}]}]},"practicalAccordionItems":[{"id":"pickup","title":"接送資訊","preview":"濟州市區飯店大廳接送","content":["08:30-09:00 之間於飯店大廳接您","約 17:30-18:00 返回下車","可事先詢問機場接送安排","實際接送時間會於前一晚確認"]},{"id":"walking","title":"步行與地形","preview":"整體中等，大多數旅客都能負擔","content":["全日總步行約 4-6 公里","石文化公園：以平路為主，部分地面略不平整","日出樂園：包含洞穴與庭園步道，部分路面可能偏濕或略不平","城山日出峰：可選擇登頂，約 20 分鐘，上坡較陡","建議穿著止滑、好走的鞋子"]},{"id":"weather","title":"天氣與臨時調整","preview":"多數天候皆可出發，必要時會微調","content":["小雨通常照常出發","若雨勢較大，戶外曝露較多的段落可能縮短，日出樂園的重要性會提高","若風勢偏強，涉地可支停留時間可能縮短","若景點臨時關閉，將視情況安排替代停靠點"]},{"id":"wear","title":"建議穿著與攜帶物品","preview":"好走的鞋、洋蔥式穿法、輕薄外套","content":["抓地力較好的步行鞋","方便增減的分層穿搭","輕薄防風外套","帽子與防曬用品","飲用水"]},{"id":"included","title":"費用包含 / 不包含","preview":"導覽、車輛、接送、門票","variant":"included","content":["專業英文導遊","小團或專車移動安排","濟州市區飯店接送","所有景點門票","瓶裝水","午餐（依現場自理）","個人購物支出","小費"]}],"practicalWeatherStatic":{"today":{"temp":"11°","label":"今天・晴朗"},"tomorrow":{"temp":"18°/13°","label":"明天・有短暫細雨"}},"seasonalVariations":[{"name":"春季","icon":"flower","description":"油菜花把海岸線染成金黃色","tag":"花季最美","bgClass":"bg-spring","iconColor":"text-pink-500"},{"name":"夏季","icon":"sun","description":"白天更長，綠意也更飽滿","tag":"日照最長","bgClass":"bg-summer","iconColor":"text-sky-500"},{"name":"秋季","icon":"leaf","description":"天空乾淨，視野通透度最好","tag":"景觀最佳","bgClass":"bg-autumn","iconColor":"text-amber-600"},{"name":"冬季","icon":"snow","description":"人潮較少，路線氣氛更安靜","tag":"氛圍最靜","bgClass":"bg-winter","iconColor":"text-slate-500"}],"bookingTrustItems":[{"icon":"check-circle","title":"在地合法導覽","description":"熟悉濟州東線節奏","iconBg":"bg-emerald-50/80","iconColor":"text-emerald-600"},{"icon":"route","title":"路線安排成熟","description":"東部路線節奏順","iconBg":"bg-sky-50/80","iconColor":"text-sky-600"},{"icon":"users","title":"小團更舒服","description":"最多 8 位旅客","iconBg":"bg-amber-50/80","iconColor":"text-amber-600"}],"bookingSupportSteps":[{"timing":"預訂完成後","title":"即時確認","detail":"立即收到訂單與行程摘要"},{"timing":"出發前 12 小時","title":"12 小時提醒","detail":"提供天氣更新與必要調整"},{"timing":"前一晚","title":"最終接送通知","detail":"確認實際接送時間與司機聯絡資訊"},{"timing":"出發當天早上","title":"當日路線提醒","detail":"依當天狀況提供簡短說明"},{"timing":"行程進行中","title":"逐站貼心提醒","detail":"各停靠點提供即時導覽與資訊"},{"timing":"行程結束後","title":"後續協助","detail":"補充推薦與後續協助"}],"staticQuestions":[{"id":"first-time","question":"第一次來濟州，也適合參加這條路線嗎？","answer":"很適合。這條路線把濟州的石文化、東部海岸風景與代表性景點串在一起，第一次來也能玩得很完整。"},{"id":"walking","question":"步行會不會很累？","answer":"整體不算太硬，真正比較吃體力的是城山日出峰登頂段；其餘大多數停靠點對一般旅客來說都屬中等強度。"},{"id":"rain","question":"下雨還能成行嗎？","answer":"可以。遇到雨天時，我們會更審慎安排海岸段停留時間，並提高日出樂園這類較適合天候不穩時的停靠比重。"},{"id":"parents","question":"帶長輩一起參加可以嗎？","answer":"可以。這條路線整體節奏算舒服，較曝曬或較有風的海岸段也能依情況調整。"},{"id":"children","question":"可以帶小朋友一起參加嗎？","answer":"可以，但會更適合 8 歲以上、能接受中等步行量與一整天觀光節奏的孩子。"},{"id":"order","question":"行程順序會改變嗎？","answer":"有可能。海岸段容易受到風勢、交通與現場人流影響，必要時會做局部調整，目的是讓整天玩起來更順，不是降級。"},{"id":"lunch","question":"午餐有包含嗎？","answer":"是否包含午餐，取決於您預訂的方案；這條路線一定會安排中段用餐時間。"},{"id":"why-stone-park","question":"為什麼第一站是石文化公園？","answer":"因為從這裡開場最穩，也最能替整天建立背景。先理解濟州的石與火山，再去看海岸、火山口與聚落，感受會更完整。"},{"id":"why-seopjikoji","question":"為什麼把涉地可支排在前半段？","answer":"因為它很適合先把海的情緒打開，再把最強的火山主景留給後面的城山日出峰。這樣節奏會更有層次。"},{"id":"why-lunch","question":"為什麼午餐安排在那個時間點？","answer":"因為午餐剛好能幫大家在城山前把體力與節奏整理好，下午玩起來會更舒服。"},{"id":"later-structure","question":"為什麼後半段要這樣排？","answer":"城山之後接日出樂園，能把步調柔下來；最後用城邑民俗村收尾，則讓整天不只是看風景，也留下更有人味的濟州印象。"}],"guestReviews":[{"id":1,"author":"Sarah M.","avatar":"https://images.unsplash.com/photo-1494790108377-be9c29b29330?w=100&q=80","location":"Singapore","date":"2024 年 3 月","rating":5,"title":"節奏安排得非常漂亮的一天","text":"這條路線真的很有邏輯，先從石文化公園開始，後面看到的每一站都更有感。導遊把地質背景講得很清楚，所以城山與日出樂園都不只是拍照而已。午餐時間也安排得剛剛好，下午走城山還保有體力。","helpful":24,"verified":true,"tripType":"情侶","photos":["https://images.unsplash.com/photo-1596402184320-417e7178b2cd?w=400&q=80","https://images.unsplash.com/photo-1469474968028-56623f02e42e?w=400&q=80"]},{"id":2,"author":"James K.","avatar":"https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=100&q=80","location":"Hong Kong","date":"2024 年 3 月","rating":5,"title":"一天看濟州東部，這樣排最剛好","text":"我們在韓國玩過幾次團，這一團最讓人有記憶點的就是行程順序安排得很成熟。導遊很知道什麼時候該慢下來、什麼時候該往前推。最後用民俗村收尾，也讓整天不只是在看自然風景。","helpful":18,"verified":true,"tripType":"家庭","photos":[]},{"id":3,"author":"Yuki T.","avatar":"https://images.unsplash.com/photo-1438761681033-6461ffad8d80?w=100&q=80","location":"Tokyo","date":"2024 年 2 月","rating":4,"title":"路線很棒，只是希望城山能再多停留一點","text":"整體體驗很好，石文化公園比預期更有意思，城山之後安排日出樂園也很剛好，能讓節奏緩一下。唯一的小遺憾是我會想在城山多留 15 分鐘，不過也能理解整體時間安排。","helpful":12,"verified":true,"tripType":"獨旅","photos":["https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400&q=80"]},{"id":4,"author":"Michael R.","avatar":"https://images.unsplash.com/photo-1500648767791-00dcc994a43e?w=100&q=80","location":"Sydney","date":"2024 年 2 月","rating":5,"title":"比原本預期還更完整、更有內容","text":"一開始是因為風景報名，最後最難忘的反而是整條路線的故事感。導遊會把每一站串起來，所以整天玩下來不是零散打卡，而是真的有一個完整的旅行節奏。午餐地點也不錯，小團人數少，聽解說很舒服。","helpful":31,"verified":true,"tripType":"朋友","photos":[]}],"reviewsSummary":{"averageRating":4.8,"totalReviews":127,"ratingDistribution":[{"stars":5,"count":98,"percentage":77},{"stars":4,"count":21,"percentage":17},{"stars":3,"count":6,"percentage":5},{"stars":2,"count":1,"percentage":1},{"stars":1,"count":1,"percentage":1}],"highlights":[{"label":"風景","count":89},{"label":"導遊","count":76},{"label":"節奏","count":54},{"label":"拍照景點","count":48}]}}'::jsonb
FROM public.tour_product_pages en
WHERE en.slug = 'east-signature-nature-core' AND en.locale = 'en'
ON CONFLICT (slug, locale) DO UPDATE SET
  is_published = EXCLUDED.is_published,
  tour_id = EXCLUDED.tour_id,
  title = EXCLUDED.title,
  subtitle = EXCLUDED.subtitle,
  region_label = EXCLUDED.region_label,
  duration_label = EXCLUDED.duration_label,
  stops_count = EXCLUDED.stops_count,
  rating_avg = EXCLUDED.rating_avg,
  review_count = EXCLUDED.review_count,
  badges = EXCLUDED.badges,
  hero_image_url = EXCLUDED.hero_image_url,
  thumbnail_url = EXCLUDED.thumbnail_url,
  card_short_description = EXCLUDED.card_short_description,
  seo_title = EXCLUDED.seo_title,
  meta_description = EXCLUDED.meta_description,
  headline_line_1 = EXCLUDED.headline_line_1,
  headline_line_2 = EXCLUDED.headline_line_2,
  price_amount_label = EXCLUDED.price_amount_label,
  price_currency = EXCLUDED.price_currency,
  price_per = EXCLUDED.price_per,
  detail_payload = EXCLUDED.detail_payload,
  updated_at = NOW();

COMMIT;
